import React, { useMemo } from "react";
import HourlyItem from "./HourlyItem";

/**
 * items: [{ dt, temp, pop, weather: [{ icon, description }] }, ...]
 */
export default function Hourly({ items = [] }) {
  const hours = useMemo(() => items.map((h, idx) => {
    const label = idx === 0
      ? "Now"
      : new Date(h.dt * 1000).toLocaleTimeString([], { hour: "numeric" });
    const icon = h?.weather?.[0]?.icon ?? "01d";
    const desc = h?.weather?.[0]?.description ?? "";
    return {
      key: h.dt ?? idx,
      label,
      temp: Math.round(h.temp ?? 0),
      pop: typeof h.pop === "number" ? Math.round(h.pop * 100) : null, // % precipitation
      icon,
      desc,
    };
  }), [items]);

  if (!hours.length) {
    return (
      <div className="px-4 py-3 text-white/60 text-sm">
        Hourly forecast unavailable.
      </div>
    );
  }

  return (
    <div className="relative">
      {/* gradient edges */}
      <div className="pointer-events-none absolute left-0 top-0 h-full w-8 bg-gradient-to-r from-black/40 to-transparent z-10" />
      <div className="pointer-events-none absolute right-0 top-0 h-full w-8 bg-gradient-to-l from-black/40 to-transparent z-10" />

      <div
        className="px-4 flex gap-3 overflow-x-auto snap-x snap-mandatory scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent"
      >
        {hours.map(h => (
          <HourlyItem
            key={h.key}
            label={h.label}
            temp={h.temp}
            pop={h.pop}
            icon={h.icon}
            desc={h.desc}
          />
        ))}
      </div>
    </div>
  );
}
